/**
 * Look up an HMS error description from the MQTT attr/code pair.
 */
function lookupHmsError(attr, code) {
  const attrHex = (attr >>> 0).toString(16).padStart(8, "0");
  const codeHex = (code >>> 0).toString(16).padStart(8, "0");

  // Try full 16-char ecode first (most specific — includes slot info)
  const fullKey = attrHex + codeHex;
  if (HMS_CODES[fullKey]) return HMS_CODES[fullKey];

  // Short key: module(4) + error(4)
  const key = attrHex.slice(0, 4) + "_" + codeHex.slice(4, 8);
  if (HMS_CODES[key]) return HMS_CODES[key];

  // Generic module (e.g., 0701 → 0700)
  const genericKey = attrHex.slice(0, 2) + "00_" + codeHex.slice(4, 8);
  if (HMS_CODES[genericKey]) return HMS_CODES[genericKey];

  // FF wildcard (e.g., 07FF, 12FF)
  const wildcardKey = attrHex.slice(0, 2) + "FF_" + codeHex.slice(4, 8);
  if (HMS_CODES[wildcardKey]) return HMS_CODES[wildcardKey];

  // AMS Lite (12xx) → AMS (07xx) mapping
  if (attrHex.startsWith("12")) {
    const amsAttr = "07" + attrHex.slice(2);
    const amsFull = amsAttr + codeHex;
    if (HMS_CODES[amsFull]) return HMS_CODES[amsFull].replace(/\bAMS\b/g, "AMS Lite");
    const amsKey = "07" + attrHex.slice(2, 4) + "_" + codeHex.slice(4, 8);
    if (HMS_CODES[amsKey]) return HMS_CODES[amsKey].replace(/\bAMS\b/g, "AMS Lite");
    // Map sub-module: 12xx_82xx → 07xx_62xx (slot offset -0x20)
    const subMod = parseInt(attrHex.slice(4, 6), 16);
    if (subMod >= 0x80) {
      const amsSubMod = (subMod - 0x20).toString(16).padStart(2, "0");
      const mappedFull = "07" + attrHex.slice(2, 4) + amsSubMod + attrHex.slice(6, 8) + codeHex;
      if (HMS_CODES[mappedFull]) return HMS_CODES[mappedFull].replace(/\bAMS\b/g, "AMS Lite");
    }
  }

  return null;
}

function formatHmsCode(attr, code) {
  const attrHex = (attr >>> 0).toString(16).padStart(8, "0").toUpperCase();
  const codeHex = (code >>> 0).toString(16).padStart(8, "0").toUpperCase();
  return attrHex.slice(0, 4) + "-" + attrHex.slice(4, 8) + "-" + codeHex.slice(0, 4) + "-" + codeHex.slice(4, 8);
}

module.exports = { lookupHmsError, formatHmsCode, HMS_CODES };
